import React from 'react';
import Header from './components/Header';
import HeroSection from './components/HeroSection';
import ShippingCalculator from './components/ShippingCalculator';
import ProcessSection from './components/ProcessSection';
import PricingTable from './components/PricingTable';
import Footer from './components/Footer';

function App() {
  return (
    // Tối ưu: Đổi sang font-sans làm mặc định để dễ đọc, dùng màu nền bg-surface
    <div className="min-h-screen bg-surface font-sans text-gray-800 flex flex-col">
      <Header />
      {/* Thêm flex-grow để đảm bảo Footer luôn bị đẩy xuống đáy màn hình */}
      <main className="flex-grow">
        <HeroSection />
        <ShippingCalculator />
        <ProcessSection />
        <PricingTable />
      </main>
      <Footer />
    </div>
  );
}

export default App;
